function createRectangleFlag(source: string): FlagIcon {
  return function RectangleFlag({ title }) {
    return <img src={source} alt="" title={title} aria-hidden="true" />;
  };
}

const untitledRectangleFlags = Object.fromEntries(
  Object.entries(rectangleFlagSources).map(([country, source]) => [
    country,
    createRectangleFlag(source),
  ]),
) as Record<string, FlagIcon>;

const flags = {
  ...(fallbackFlags as Record<string, FlagIcon>),
  ...untitledRectangleFlags,
};

interface CountryFlagProps extends HTMLAttributes<HTMLSpanElement> {
  country: string;
  countryName?: string;
}

function CountryFlag({ country, countryName = country, className, ...props }: CountryFlagProps) {
  const Flag = flags[country.toUpperCase()];

  if (!Flag) return null;

  return (
    <span
      className={cn(className, "rounded overflow-hidden")}
      role="img"
      aria-label={countryName}
      {...props}
    >
      <Flag title={countryName} />
    </span>
  );
}

export { CountryFlag, flags, rectangleFlagSources };
export type { CountryFlagProps };
